module comparator_64bit(  
    input [63:0] A,  
    input [63:0] B,  
    output reg [2:0] result  
);  
  wire [63:0] _tap_A = A & {64{1'b1}};

    always @* begin  
        if (A < B)  
            result = 3'b001;  
        else if (A == B)  
            result = 3'b010;  
        else  
            result = 3'b100;  
    end  
endmodule
